import React from 'react';
import { Calendar, Plane, Lightbulb } from 'lucide-react';

/**
 * Features component - Displays the main feature cards in a grid layout with Lucide icons
 * @param {Object} props - Component props
 * @param {Array} props.features - Array of feature objects with icon, title, description, and iconComponent
 */
const Features = ({ 
  features = [
    {
      icon: Calendar,
      title: "Track Leave",
      description: "Monitor your EL, SL, and CL balances with real-time updates",
      iconColor: "text-purple-600"
    },
    {
      icon: Plane,
      title: "Plan Vacations",
      description: "Plan multi-day vacations with smart date validation",
      iconColor: "text-green-600"
    },
    {
      icon: Lightbulb,
      title: "AI Insights",
      description: "Get smart recommendations for optimal vacation timing",
      iconColor: "text-blue-600"
    }
  ]
}) => {
  return (
    <section aria-labelledby="features-heading" className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-8 mb-16">
      <h2 id="features-heading" className="sr-only">Key Features</h2>
      {features.map((feature, index) => {
        const IconComponent = feature.icon;
        return (
          <article 
            key={index} 
            className="bg-white rounded-lg shadow-sm p-6 hover:shadow-md transition-shadow duration-200 text-center"
            aria-labelledby={`feature-${index}-title`}
          >
            <div 
              className="w-12 h-12 mx-auto mb-4 rounded-full bg-purple-50 flex items-center justify-center"
              aria-label={`${feature.title} feature icon`}
            >
              <IconComponent 
                className={`w-6 h-6 ${feature.iconColor}`}
                aria-hidden="true"
              />
            </div>
            <h3 id={`feature-${index}-title`} className="text-lg font-semibold mb-2 text-gray-900">
              {feature.title}
            </h3>
            <p className="text-sm sm:text-base text-gray-600">
              {feature.description}
            </p>
          </article>
        );
      })}
    </section>
  );
};

export default Features;
